CREATE INDEX "IX_Announcements_EventId" ON "Announcements" ("EventId");

CREATE UNIQUE INDEX "IX_Bookings_CheckInToken" ON "Bookings" ("CheckInToken");

CREATE INDEX "IX_Bookings_EventId" ON "Bookings" ("EventId");

CREATE UNIQUE INDEX "IX_Bookings_UserId_EventId" ON "Bookings" ("UserId", "EventId") WHERE "Status" = 'Confirmed';

CREATE INDEX "IX_Events_CategoryId" ON "Events" ("CategoryId");

CREATE INDEX "IX_Events_CreatedById" ON "Events" ("CreatedById");

CREATE INDEX "IX_EventTags_TagId" ON "EventTags" ("TagId");

CREATE INDEX "IX_HostSubscriptions_HostId" ON "HostSubscriptions" ("HostId");

CREATE INDEX "IX_Notifications_EventId" ON "Notifications" ("EventId");

CREATE INDEX "IX_Notifications_UserId" ON "Notifications" ("UserId");

CREATE INDEX "IX_PayoutRequests_OrganizerId" ON "PayoutRequests" ("OrganizerId");

CREATE INDEX "IX_ReviewReplies_ReviewId" ON "ReviewReplies" ("ReviewId");

CREATE INDEX "IX_ReviewReplies_UserId" ON "ReviewReplies" ("UserId");

CREATE UNIQUE INDEX "IX_Reviews_EventId_UserId" ON "Reviews" ("EventId", "UserId");

